() =>
    createValidate(
      RT.object({
        email: RT.string(),
        password: RT.string(),
        acceptedTerms: RT.literal(true),
        profile: RT.object({
          firstName: RT.string(),
          lastName: RT.string(),
          age: RT.optional(RT.number()),
        }),
      })
    )

{
    build: () => {
      const check = typia.createIs<RegistrationForm>();
      return (v) => check(v);
    },
    buildErrors: () => {
      const val = typia.createValidate<RegistrationForm>();
      return (v) => val(v).success;
    },
  }

